using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator;

    public PriceCalculatorTests()
    {
        _calculator = new PriceCalculator();
    }

    // --- CalculateTotal: DataRow for simple inline cases ---

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 2, 0.0, 20.00, DisplayName = "Two items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Multiple items, 8% tax")]
    [DataRow(0.00, 5, 0.10, 0.00, DisplayName = "Zero price")]
    [DataRow(99.99, 0, 0.20, 0.00, DisplayName = "Zero quantity")]
    [DataRow(100.00, 1, 1.0, 200.00, DisplayName = "Max tax rate (100%)")]
    public void CalculateTotal_WithValidInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- CalculateTotal: DynamicData with ValueTuples for edge / boundary cases ---

    [TestMethod]
    [DynamicData(nameof(CalculateTotalBoundaryData))]
    public void CalculateTotal_BoundaryCases_ReturnsExpectedTotal(
        decimal unitPrice, int quantity, decimal taxRate, decimal expected)
    {
        var result = _calculator.CalculateTotal(unitPrice, quantity, taxRate);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal unitPrice, int quantity, decimal taxRate, decimal expected)>
        CalculateTotalBoundaryData =>
    [
        (0.01m, 1, 0m, 0.01m),
        (0.01m, 1, 1m, 0.02m),
        (999999.99m, 1, 0m, 999999.99m),
        (50m, 10, 0.05m, 525.00m),
    ];

    // --- CalculateTotal: invalid argument tests ---

    [TestMethod]
    public void CalculateTotal_NegativeQuantity_ThrowsArgumentOutOfRange()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, -1, 0.1m));

        Assert.AreEqual("quantity", ex.ParamName);
    }

    [TestMethod]
    public void CalculateTotal_NegativeUnitPrice_ThrowsArgumentOutOfRange()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(-5m, 1, 0.1m));

        Assert.AreEqual("unitPrice", ex.ParamName);
    }

    [TestMethod]
    [DataRow(-0.01, DisplayName = "Tax rate below zero")]
    [DataRow(1.01, DisplayName = "Tax rate above 1")]
    public void CalculateTotal_InvalidTaxRate_ThrowsArgumentOutOfRange(double taxRate)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, 1, (decimal)taxRate));

        Assert.AreEqual("taxRate", ex.ParamName);
    }

    // --- ApplyDiscount: DataRow for common scenarios ---

    [TestMethod]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% off")]
    [DataRow(200.00, 25.0, 150.00, DisplayName = "25% off")]
    [DataRow(50.00, 0.0, 50.00, DisplayName = "No discount")]
    [DataRow(80.00, 100.0, 0.00, DisplayName = "100% discount (free)")]
    [DataRow(49.99, 50.0, 24.995, DisplayName = "50% off odd price")]
    public void ApplyDiscount_WithValidInputs_ReturnsDiscountedPrice(
        double price, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- ApplyDiscount: invalid discount ---

    [TestMethod]
    [DataRow(-1.0, DisplayName = "Negative discount")]
    [DataRow(100.01, DisplayName = "Discount above 100%")]
    public void ApplyDiscount_InvalidDiscountPercent_ThrowsArgumentOutOfRange(double discountPercent)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discountPercent));

        Assert.AreEqual("discountPercent", ex.ParamName);
    }

    // --- FormatPrice ---

    [TestMethod]
    [DataRow(19.99, "$", "$19.99", DisplayName = "USD")]
    [DataRow(19.99, "€", "€19.99", DisplayName = "Euro")]
    [DataRow(1000.00, "£", "£1000.00", DisplayName = "GBP large")]
    [DataRow(0.50, "$", "$0.50", DisplayName = "Sub-dollar")]
    public void FormatPrice_WithCurrencySymbol_ReturnsFormattedString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void FormatPrice_DefaultCurrency_UsesDollarSign()
    {
        var result = _calculator.FormatPrice(9.99m);

        Assert.AreEqual("$9.99", result);
    }
}

